// ===================================================================
// 제4장: 데이터 구조화 (v5.5) - 벡터와 동적 데이터 관리
// ===================================================================
//
// 철학: "데이터의 집적과 확장"
//
// v5.0-v5.4: 개별 데이터의 형태와 패턴
// v5.5: 그 데이터들을 유동적으로 관리 ← 여기!
//
// 벡터는:
// - 동적 크기의 배열
// - 힙 메모리 기반
// - 런타임에 데이터 추가/삭제 가능
// - 소유권과 참조의 복잡한 상호작용
//
// ===================================================================

fn main() {
    println!("╔═══════════════════════════════════════════════════════════╗");
    println!("║   v5.5: 벡터와 동적 데이터 관리 (Vectors & Collections)  ║");
    println!("║        \"데이터의 집적과 확장\"을 통한 대규모 처리        ║");
    println!("╚═══════════════════════════════════════════════════════════╝\n");

    section_1_vector_basics();
    println!();
    section_2_vector_creation();
    println!();
    section_3_vector_access();
    println!();
    section_4_vector_iteration();
    println!();
    section_5_vector_modification();
    println!();
    section_6_iterators_and_methods();
    println!();
    section_7_advanced_real_world();
}

// ===================================================================
// Section 1: 벡터 기본 (Vector Basics)
// ===================================================================
//
// Vec<T>는 가장 기본적인 동적 컬렉션입니다.
//
fn section_1_vector_basics() {
    println!("▶ Section 1: 벡터 기본");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 1-1. 빈 벡터 생성
    // ─────────────────────────────────────────
    println!("  [1-1] 빈 벡터 생성");

    let mut numbers: Vec<i32> = Vec::new();
    println!("    빈 벡터 생성: {:?}", numbers);
    println!("    길이: {}, 용량: {}", numbers.len(), numbers.capacity());
    println!();

    // ─────────────────────────────────────────
    // 1-2. push로 데이터 추가
    // ─────────────────────────────────────────
    println!("  [1-2] push로 데이터 추가");

    numbers.push(10);
    numbers.push(20);
    numbers.push(30);

    println!("    추가 후: {:?}", numbers);
    println!("    길이: {}, 용량: {}", numbers.len(), numbers.capacity());
    println!("    → 용량이 자동으로 확대됨 (성능 최적화)\n");

    // ─────────────────────────────────────────
    // 1-3. 스택 메모리 vs 힙 메모리
    // ─────────────────────────────────────────
    println!("  [1-3] 메모리 구조");

    println!("    배열 (고정):  [10, 20, 30] (스택에 직접 저장)");
    println!("    벡터 (동적):  포인터 → 힙의 데이터");
    println!("    → 벡터는 내부적으로 '포인터, 길이, 용량'을 저장\n");

    // ─────────────────────────────────────────
    // 1-4. 벡터의 크기 관리
    // ─────────────────────────────────────────
    println!("  [1-4] 벡터의 크기 관리");

    let mut vec = Vec::new();
    println!("    초기 상태: len={}, capacity={}", vec.len(), vec.capacity());

    for i in 0..10 {
        vec.push(i);
        if i == 0 || i == 2 || i == 4 || i == 7 {
            println!("    i={}: len={}, capacity={}", i, vec.len(), vec.capacity());
        }
    }
    println!("    → 필요할 때마다 자동으로 용량 증가\n");

    println!("  💡 핵심: 벡터는 동적 크기와 자동 메모리 관리를 제공합니다.\n");
}

// ===================================================================
// Section 2: 벡터 생성 방법 (Vector Creation)
// ===================================================================
//
// 벡터를 생성하는 여러 방법들
//
fn section_2_vector_creation() {
    println!("▶ Section 2: 벡터 생성 방법");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 2-1. Vec::new()
    // ─────────────────────────────────────────
    println!("  [2-1] Vec::new() - 빈 벡터");

    let _v1: Vec<i32> = Vec::new();
    println!("    let v: Vec<i32> = Vec::new();\n");

    // ─────────────────────────────────────────
    // 2-2. vec! 매크로
    // ─────────────────────────────────────────
    println!("  [2-2] vec! 매크로 - 초기값과 함께");

    let v2 = vec![1, 2, 3, 4, 5];
    println!("    let v = vec![1, 2, 3, 4, 5];");
    println!("    결과: {:?}\n", v2);

    // ─────────────────────────────────────────
    // 2-3. Vec::with_capacity()
    // ─────────────────────────────────────────
    println!("  [2-3] Vec::with_capacity() - 미리 용량 할당");

    let mut v3: Vec<String> = Vec::with_capacity(100);
    println!("    let v: Vec<String> = Vec::with_capacity(100);");
    println!("    len={}, capacity={}", v3.len(), v3.capacity());
    println!("    → 100개 미리 할당하므로 push할 때 재할당 없음\n");

    for i in 0..5 {
        v3.push(format!("item_{}", i));
    }
    println!("    5개 추가 후: len={}, capacity={}", v3.len(), v3.capacity());
    println!("    → 용량 재할당이 발생하지 않음 (성능 향상)\n");

    // ─────────────────────────────────────────
    // 2-4. 반복으로 벡터 생성
    // ─────────────────────────────────────────
    println!("  [2-4] 반복으로 벡터 생성");

    let v4: Vec<i32> = (1..=5).collect();
    println!("    let v: Vec<i32> = (1..=5).collect();");
    println!("    결과: {:?}\n", v4);

    println!("  💡 핵심: 용도에 따라 적절한 생성 방법을 선택하세요.\n");
}

// ===================================================================
// Section 3: 벡터 접근 (Vector Access)
// ===================================================================
//
// 벡터의 데이터에 접근하는 안전한 방법들
//
fn section_3_vector_access() {
    println!("▶ Section 3: 벡터 접근");
    println!("─────────────────────────────────────────\n");

    let vec = vec!["A", "B", "C", "D", "E"];

    // ─────────────────────────────────────────
    // 3-1. 인덱싱 (위험)
    // ─────────────────────────────────────────
    println!("  [3-1] 인덱싱 - 직접 접근 (위험함)");

    println!("    vec[0] = {}", vec[0]);
    println!("    vec[4] = {}", vec[4]);

    // vec[10] = ...  // ❌ panic!
    // println!("    vec[10] = {}", vec[10]);  // 범위 밖이면 패닉!
    println!("    vec[10] 접근 → 패닉! (범위 초과)\n");

    // ─────────────────────────────────────────
    // 3-2. .get() (안전)
    // ─────────────────────────────────────────
    println!("  [3-2] .get() - 안전한 접근");

    match vec.get(0) {
        Some(item) => println!("    vec.get(0) = Some(\"{}\")", item),
        None => println!("    vec.get(0) = None"),
    }

    match vec.get(10) {
        Some(item) => println!("    vec.get(10) = Some(\"{}\")", item),
        None => println!("    vec.get(10) = None (범위 초과)"),
    }
    println!("    → .get()은 Option을 반환하므로 안전\n");

    // ─────────────────────────────────────────
    // 3-3. 첫 번째와 마지막
    // ─────────────────────────────────────────
    println!("  [3-3] 첫 번째와 마지막");

    println!("    vec.first() = {:?}", vec.first());
    println!("    vec.last() = {:?}", vec.last());
    println!();

    println!("  💡 핵심: 인덱싱 대신 .get()을 사용하여 안전하게 접근하세요.\n");
}

// ===================================================================
// Section 4: 벡터 순회 (Vector Iteration)
// ===================================================================
//
// 벡터의 모든 데이터를 처리하는 방법들
//
fn section_4_vector_iteration() {
    println!("▶ Section 4: 벡터 순회");
    println!("─────────────────────────────────────────\n");

    let numbers = vec![1, 2, 3, 4, 5];

    // ─────────────────────────────────────────
    // 4-1. for in loop (불변 참조)
    // ─────────────────────────────────────────
    println!("  [4-1] for in loop (&numbers - 불변 참조)");

    for num in &numbers {
        print!(" {}", num);
    }
    println!();
    println!("    numbers는 여전히 사용 가능: {:?}", numbers);
    println!("    → &를 사용하므로 소유권 유지\n");

    // ─────────────────────────────────────────
    // 4-2. for in loop (가변 참조)
    // ─────────────────────────────────────────
    println!("  [4-2] for in loop (&mut numbers - 가변 참조)");

    let mut numbers2 = vec![1, 2, 3, 4, 5];
    for num in &mut numbers2 {
        *num *= 2;  // 역참조로 수정
    }
    println!("    2배로 수정: {:?}", numbers2);
    println!("    → 루프 안에서 데이터 수정 가능\n");

    // ─────────────────────────────────────────
    // 4-3. for in loop (소유권 이동)
    // ─────────────────────────────────────────
    println!("  [4-3] for in loop (numbers - 소유권 이동)");

    let strings = vec![String::from("A"), String::from("B"), String::from("C")];
    for s in strings {  // 소유권 이동
        println!("    처리 중: {}", s);
    }
    // println!("{:?}", strings);  // ❌ 오류! strings는 소유권을 잃음
    println!("    → 루프 후 strings는 사용 불가\n");

    // ─────────────────────────────────────────
    // 4-4. iter, iter_mut, into_iter
    // ─────────────────────────────────────────
    println!("  [4-4] 반복자 메서드 비교");

    let v = vec![10, 20, 30];

    println!("    v.iter():");
    for num in v.iter() {
        print!(" {}", num);
    }
    println!();

    println!("    v.iter() 후 v 사용 가능: {:?}", v);
    println!();

    println!("  💡 핵심:");
    println!("    - for x in &vec: 불변 참조");
    println!("    - for x in &mut vec: 가변 참조");
    println!("    - for x in vec: 소유권 이동\n");
}

// ===================================================================
// Section 5: 벡터 수정 (Vector Modification)
// ===================================================================
//
// 벡터의 내용을 변경하는 방법들
//
fn section_5_vector_modification() {
    println!("▶ Section 5: 벡터 수정");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 5-1. push - 끝에 추가 (빠름)
    // ─────────────────────────────────────────
    println!("  [5-1] push() - 끝에 추가 (O(1))");

    let mut vec = vec![1, 2, 3];
    vec.push(4);
    vec.push(5);
    println!("    결과: {:?}\n", vec);

    // ─────────────────────────────────────────
    // 5-2. pop - 끝에서 제거
    // ─────────────────────────────────────────
    println!("  [5-2] pop() - 끝에서 제거");

    let removed = vec.pop();
    println!("    제거된 값: {:?}", removed);
    println!("    결과: {:?}\n", vec);

    // ─────────────────────────────────────────
    // 5-3. insert - 중간에 삽입 (느림)
    // ─────────────────────────────────────────
    println!("  [5-3] insert() - 특정 위치에 삽입 (O(n))");

    vec.insert(1, 99);
    println!("    결과: {:?}", vec);
    println!("    → 뒤의 모든 데이터를 이동시켜야 함\n");

    // ─────────────────────────────────────────
    // 5-4. remove - 특정 위치 제거
    // ─────────────────────────────────────────
    println!("  [5-4] remove() - 특정 위치 제거");

    let removed = vec.remove(1);
    println!("    제거된 값: {}", removed);
    println!("    결과: {:?}\n", vec);

    // ─────────────────────────────────────────
    // 5-5. clear - 모두 제거
    // ─────────────────────────────────────────
    println!("  [5-5] clear() - 모든 데이터 제거");

    vec.clear();
    println!("    결과: {:?}", vec);
    println!("    길이: {}\n", vec.len());

    println!("  💡 핵심:");
    println!("    - push: O(1) - 항상 빠름");
    println!("    - insert(0, ...): O(n) - 느림");
    println!("    - 성능이 중요하면 뒤에만 추가하세요.\n");
}

// ===================================================================
// Section 6: 반복자와 고급 메서드 (Iterators & Advanced Methods)
// ===================================================================
//
// 함수형 프로그래밍 스타일의 벡터 처리
//
fn section_6_iterators_and_methods() {
    println!("▶ Section 6: 반복자와 고급 메서드");
    println!("─────────────────────────────────────────\n");

    let numbers = vec![1, 2, 3, 4, 5, 6];

    // ─────────────────────────────────────────
    // 6-1. map - 변환
    // ─────────────────────────────────────────
    println!("  [6-1] map() - 각 요소 변환");

    let doubled: Vec<i32> = numbers.iter().map(|n| n * 2).collect();
    println!("    원본: {:?}", numbers);
    println!("    2배: {:?}", doubled);
    println!();

    // ─────────────────────────────────────────
    // 6-2. filter - 필터링
    // ─────────────────────────────────────────
    println!("  [6-2] filter() - 조건에 맞는 요소만");

    let evens: Vec<i32> = numbers.iter().filter(|&&n| n % 2 == 0).copied().collect();
    println!("    짝수만: {:?}", evens);
    println!();

    // ─────────────────────────────────────────
    // 6-3. fold - 누적
    // ─────────────────────────────────────────
    println!("  [6-3] fold() - 누적 계산");

    let sum = numbers.iter().fold(0, |acc, &n| acc + n);
    let product = numbers.iter().fold(1, |acc, &n| acc * n);

    println!("    합계: {}", sum);
    println!("    곱: {}\n", product);

    // ─────────────────────────────────────────
    // 6-4. 체이닝
    // ─────────────────────────────────────────
    println!("  [6-4] 메서드 체이닝");

    let result: Vec<i32> = numbers
        .iter()
        .filter(|&&n| n > 2)
        .map(|n| n * 2)
        .collect();

    println!("    filter(n > 2).map(n * 2): {:?}", result);
    println!();

    // ─────────────────────────────────────────
    // 6-5. any, all, find
    // ─────────────────────────────────────────
    println!("  [6-5] 탐색 메서드");

    let has_even = numbers.iter().any(|&n| n % 2 == 0);
    let all_positive = numbers.iter().all(|&n| n > 0);
    let first_even = numbers.iter().find(|&&n| n % 2 == 0);

    println!("    짝수 존재: {}", has_even);
    println!("    모두 양수: {}", all_positive);
    println!("    첫 짝수: {:?}\n", first_even);

    println!("  💡 핵심: 반복자 메서드로 함수형 스타일 처리가 가능합니다.\n");
}

// ===================================================================
// Section 7: 실전 예제 - 동적 레코드 매니저 (Advanced Real-World)
// ===================================================================
//
// 모든 개념을 종합한 실제 시스템
//
fn section_7_advanced_real_world() {
    println!("▶ Section 7: 실전 예제 - 동적 레코드 매니저");
    println!("─────────────────────────────────────────\n");

    #[derive(Debug, Clone)]
    struct GogsLog {
        id: u32,
        message: String,
        level: LogLevel,
    }

    #[derive(Debug, Clone, PartialEq)]
    enum LogLevel {
        Info,
        Warning,
        Error,
    }

    // ─────────────────────────────────────────
    // 7-1. 기본 레코드 관리
    // ─────────────────────────────────────────
    println!("  [7-1] 동적 레코드 추가");

    let mut logs: Vec<GogsLog> = Vec::with_capacity(10);

    logs.push(GogsLog {
        id: 1,
        message: String::from("시스템 시작"),
        level: LogLevel::Info,
    });
    logs.push(GogsLog {
        id: 2,
        message: String::from("메모리 부족"),
        level: LogLevel::Warning,
    });
    logs.push(GogsLog {
        id: 3,
        message: String::from("연결 실패"),
        level: LogLevel::Error,
    });

    println!("    총 로그: {}개", logs.len());
    println!("    용량: {} (미리 할당)\n", logs.capacity());

    // ─────────────────────────────────────────
    // 7-2. 필터링과 변환
    // ─────────────────────────────────────────
    println!("  [7-2] 에러 로그만 추출");

    let errors: Vec<&GogsLog> = logs.iter()
        .filter(|log| log.level == LogLevel::Error)
        .collect();

    for log in &errors {
        println!("    [ERROR] #{}: {}", log.id, log.message);
    }
    println!();

    // ─────────────────────────────────────────
    // 7-3. 메시지 추출 및 변환
    // ─────────────────────────────────────────
    println!("  [7-3] 모든 메시지 추출");

    let messages: Vec<String> = logs.iter()
        .map(|log| format!("[{:?}] {}", log.level, log.message))
        .collect();

    for msg in &messages {
        println!("    {}", msg);
    }
    println!();

    // ─────────────────────────────────────────
    // 7-4. 통계 계산
    // ─────────────────────────────────────────
    println!("  [7-4] 로그 통계");

    let info_count = logs.iter().filter(|l| l.level == LogLevel::Info).count();
    let warning_count = logs.iter().filter(|l| l.level == LogLevel::Warning).count();
    let error_count = logs.iter().filter(|l| l.level == LogLevel::Error).count();

    println!("    INFO: {}, WARNING: {}, ERROR: {}", info_count, warning_count, error_count);
    println!();

    // ─────────────────────────────────────────
    // 7-5. 레코드 수정
    // ─────────────────────────────────────────
    println!("  [7-5] 특정 로그 찾기 및 수정");

    if let Some(log) = logs.iter_mut().find(|l| l.id == 2) {
        log.message = String::from("메모리 정리 완료");
        log.level = LogLevel::Info;
    }

    println!("    ID 2 업데이트:");
    println!("    {:?}\n", logs[1]);

    // ─────────────────────────────────────────
    // 7-6. 성능 고려사항 시연
    // ─────────────────────────────────────────
    println!("  [7-6] 성능 비교");

    let mut slow_vec = Vec::new();
    let mut fast_vec = Vec::with_capacity(1000);

    // 느린 방식: 용량 재할당
    for i in 0..1000 {
        slow_vec.push(i);
    }

    // 빠른 방식: 미리 할당
    for i in 0..1000 {
        fast_vec.push(i);
    }

    println!("    slow_vec 용량: {}", slow_vec.capacity());
    println!("    fast_vec 용량: {}", fast_vec.capacity());
    println!("    → with_capacity()로 재할당 횟수 최소화\n");

    println!("  💡 핵심: 벡터는 데이터의 집적과 확장을 안전하게 제어합니다.\n");
}

